contracts/CloudGreenCredential.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/access/Ownable.sol";

contract CloudGreenCredential is Ownable {
    struct Credential {
        address subject;
        string credentialId;
        uint256 issuedAt;
    }

    mapping(bytes32 => Credential) private credentials;

    event CredentialIssued(bytes32 indexed credentialHash, address indexed subject, string credentialId, uint256 issuedAt);

    constructor(address initialOwner) Ownable(initialOwner) {}

    function issueCredential(address subject, string calldata credentialId) external onlyOwner returns (bytes32) {
        bytes32 credentialHash = keccak256(abi.encodePacked(subject, credentialId));
        credentials[credentialHash] = Credential({
            subject: subject,
            credentialId: credentialId,
            issuedAt: block.timestamp
        });

        emit CredentialIssued(credentialHash, subject, credentialId, block.timestamp);
        return credentialHash;
    }

    function getCredential(bytes32 credentialHash) external view returns (Credential memory) {
        return credentials[credentialHash];
    }
}

